          }
        }
      },
      "Order": {
        "shape": {
          "type": "Record",
          "attributes": {
            "assignee": {
              "type": "Entity",
              "name": "Guest",
              "required": true
            },
            "project": {
              "type": "String",
              "required": true
            }
          }
        }
      },
      "Document": {
        "shape": {
          "type": "Record",
          "attributes": {
            "project": {
              "type": "String",
              "required": true
            }
          }
        }
      }
    },
    "actions": {
      "delete": {
        "appliesTo": {
          "principalTypes": [
            "Guest",
            "Auditor"
          ],
          "resourceTypes": [
            "Ticket",
            "Order",
            "Document"
          ]
        }
      },
      "write": {
        "appliesTo": {
          "principalTypes": [
            "Guest",
            "Auditor"
          ],
          "resourceTypes": [
            "Ticket",
            "Order",
            "Document"
          ]
        }
      },
      "create": {
        "appliesTo": {
          "principalTypes": [
            "Guest",
            "Auditor"
          ],
          "resourceTypes": [
            "Ticket",
            "Order",
            "Document"
          ]
        }
      }
    }
  }
}

Policies:
- POLICY_1
  permit (
    principal is ProjectHub::Auditor,
    action == ProjectHub::Action::"write",
    resource is ProjectHub::Ticket
  ) when {
    resource has owner && resource.owner == principal
  };
- POLICY_2
  permit (
    principal is ProjectHub::Guest,
    action == ProjectHub::Action::"create",
    resource is ProjectHub::Document
  ) when {
    resource has project && principal has project && resource.project == principal.project
  };
- POLICY_3
  permit (
    principal is ProjectHub::Guest,
    action == ProjectHub::Action::"write",
    resource is ProjectHub::Order
  ) when {
    resource has assignee && resource.assignee == principal
  };
- POLICY_4
  forbid (
    principal is ProjectHub::Guest,
    action == ProjectHub::Action::"delete",
    resource is ProjectHub::Order
  ) when {
    resource has project && principal has project && resource.project != principal.project
  };

